INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u10-l1','B1','listening','b1-u10','normal',1,'Second Conditional','If + past simple, would + base verb — tình huống giả định hiện tại',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u10-l1-p1','b1-u10-l1','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu điều kiện loại 2 ĐÚNG:","options":[{"id":"a","text":"If I will have time, I will call you."},{"id":"b","text":"If I had time, I would call you."},{"id":"c","text":"If I would have time, I call you."}],"correctOptionId":"b","explanationVi":"Loại 2: If + past simple, would + base verb."}'::jsonb),
 ('b1-u10-l1-p2','b1-u10-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền vào chỗ trống: ''If I ___ (be) you, I would apologise.''","acceptedAnswers":["were"],"explanationVi":"If I were you — were cho mọi chủ ngữ."}'::jsonb),
 ('b1-u10-l1-p3','b1-u10-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối mệnh đề:","pairs":[{"left":"If I had a car","right":"I would drive to work."},{"left":"If I were you","right":"I would tell the truth."},{"left":"If she studied harder","right":"she would pass the exam."}],"explanationVi":"Ghép đúng từng cặp điều kiện."}'::jsonb),
 ('b1-u10-l1-p4','b1-u10-l1','error_correction',4,'practice','medium',false,'{"question":"Sửa lỗi: ''If I would have more money, I would travel.''","acceptedAnswers":["If I had more money, I would travel."],"explanationVi":"Mệnh đề if không dùng would → past simple."}'::jsonb),
 ('b1-u10-l1-p5','b1-u10-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh: ''Nếu tôi là bạn, tôi sẽ xin lỗi.''","sourceText":"Nếu tôi là bạn, tôi sẽ xin lỗi.","acceptedAnswers":["If I were you, I would apologise.","If I were you, I would say sorry."],"explanationVi":"If I were you, I would apologise."}'::jsonb),
 ('b1-u10-l1-p6','b1-u10-l1','multiple_choice',6,'practice','medium',false,'{"question":"Câu điều kiện loại mấy? ''If it rains, I will stay home.''","options":[{"id":"a","text":"Loại 1"},{"id":"b","text":"Loại 2"},{"id":"c","text":"Loại 3"}],"correctOptionId":"a","explanationVi":"If + present, will + base verb → Loại 1 (thực tế)."}'::jsonb),
 ('b1-u10-l1-p7','b1-u10-l1','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành: ''She ___ (be) happier if she ___ (exercise) more.''","acceptedAnswers":["would be / exercised"],"explanationVi":"would + base verb / if + past simple."}'::jsonb),
 ('b1-u10-l1-q1','b1-u10-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG:","options":[{"id":"a","text":"If I had wings, I would fly."},{"id":"b","text":"If I would have wings, I fly."},{"id":"c","text":"If I have wings, I would fly."}],"correctOptionId":"a","explanationVi":"Loại 2: If + past simple, would + base verb."}'::jsonb),
 ('b1-u10-l1-q2','b1-u10-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''What ___ you do if you won the lottery?''","acceptedAnswers":["would"],"explanationVi":"Câu hỏi loại 2: would + S + base verb."}'::jsonb),
 ('b1-u10-l1-q3','b1-u10-l1','error_correction',10,'quiz','medium',true,'{"question":"Sửa lỗi: ''If I was you, I would tell her.''","acceptedAnswers":["If I were you, I would tell her."],"explanationVi":"If I were you (were, không phải was — formal)."}'::jsonb),
 ('b1-u10-l1-q4','b1-u10-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền vào chỗ trống: ''If he ___ (study) harder, he ___ (pass) the exam.''","acceptedAnswers":["studied / would pass"],"explanationVi":"If + past simple, would + base verb."}'::jsonb),
 ('b1-u10-l1-q5','b1-u10-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối loại điều kiện với đặc điểm:","pairs":[{"left":"Loại 1","right":"If + present, will + base"},{"left":"Loại 2","right":"If + past, would + base"}],"explanationVi":"Phân biệt loại 1 và loại 2."}'::jsonb),
 ('b1-u10-l1-q6','b1-u10-l1','translation',13,'quiz','hard',true,'{"question":"Dịch: ''Nếu cô ấy tập thể dục nhiều hơn, cô ấy sẽ cảm thấy tốt hơn.''","sourceText":"Nếu cô ấy tập thể dục nhiều hơn, cô ấy sẽ cảm thấy tốt hơn.","acceptedAnswers":["If she exercised more, she would feel better."],"explanationVi":"If + past simple, would + base verb."}'::jsonb),
 ('b1-u10-l1-q7','b1-u10-l1','sentence_ordering',14,'quiz','hard',true,'{"question":"Sắp xếp thành câu điều kiện loại 2 đúng:","tokens":["If","I","had","more","time","I","would","learn","guitar"],"correctOrder":[0,1,2,3,4,5,6,7,8],"explanationVi":"If I had more time, I would learn guitar."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u10-l2','B1','listening','b1-u10','normal',2,'Third Conditional','If + past perfect, would have + V3 — hối tiếc về quá khứ',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u10-l2-p1','b1-u10-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu điều kiện loại 3 ĐÚNG:","options":[{"id":"a","text":"If I had studied, I would have passed."},{"id":"b","text":"If I would have studied, I would have passed."},{"id":"c","text":"If I studied, I would have passed."}],"correctOptionId":"a","explanationVi":"Loại 3: If + past perfect, would have + V3."}'::jsonb),
 ('b1-u10-l2-p2','b1-u10-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền vào chỗ trống: ''If she ___ (not miss) the bus, she ___ (arrive) on time.''","acceptedAnswers":["hadn''t missed / would have arrived"],"explanationVi":"If + past perfect negative, would have + V3."}'::jsonb),
 ('b1-u10-l2-p3','b1-u10-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối mệnh đề if với kết quả:","pairs":[{"left":"If I had saved more","right":"I would have bought a house."},{"left":"If he had asked","right":"I would have helped him."},{"left":"If she hadn''t been late","right":"she would have caught the train."}],"explanationVi":"Ghép đúng từng cặp điều kiện."}'::jsonb),
 ('b1-u10-l2-p4','b1-u10-l2','error_correction',4,'practice','medium',false,'{"question":"Sửa lỗi: ''If I would have known, I would have told you.''","acceptedAnswers":["If I had known, I would have told you."],"explanationVi":"Mệnh đề if: past perfect (không dùng would have)."}'::jsonb),
 ('b1-u10-l2-p5','b1-u10-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh: ''Giá mà tôi học chăm hơn, tôi đã đỗ rồi.''","sourceText":"Giá mà tôi học chăm hơn, tôi đã đỗ rồi.","acceptedAnswers":["If I had studied harder, I would have passed."],"explanationVi":"Loại 3: If + past perfect, would have + V3."}'::jsonb),
 ('b1-u10-l2-p6','b1-u10-l2','multiple_choice',6,'practice','medium',false,'{"question":"Câu nào là điều kiện loại 3?","options":[{"id":"a","text":"If I were you, I would go."},{"id":"b","text":"If I had been there, I would have helped."},{"id":"c","text":"If it rains, I will stay."}],"correctOptionId":"b","explanationVi":"If + past perfect → loại 3."}'::jsonb),
 ('b1-u10-l2-p7','b1-u10-l2','grammar_fill_blank',7,'practice','medium',false,'{"question":"Điền vào chỗ trống: ''We ___ (win) the game if we ___ (practise) more.''","acceptedAnswers":["would have won / had practised"],"explanationVi":"Loại 3 đảo mệnh đề."}'::jsonb),
 ('b1-u10-l2-q1','b1-u10-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG:","options":[{"id":"a","text":"If they had left earlier, they wouldn''t have been late."},{"id":"b","text":"If they would have left earlier, they wouldn''t have been late."},{"id":"c","text":"If they left earlier, they wouldn''t have been late."}],"correctOptionId":"a","explanationVi":"Loại 3: If + past perfect."}'::jsonb),
 ('b1-u10-l2-q2','b1-u10-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''If he ___ (study) medicine, he ___ (become) a doctor.''","acceptedAnswers":["had studied / would have become"],"explanationVi":"If + had + V3, would have + V3."}'::jsonb),
 ('b1-u10-l2-q3','b1-u10-l2','error_correction',10,'quiz','medium',true,'{"question":"Sửa lỗi: ''She would have pass if she had studied.''","acceptedAnswers":["She would have passed if she had studied."],"explanationVi":"would have + V3: passed."}'::jsonb),
 ('b1-u10-l2-q4','b1-u10-l2','translation',11,'quiz','medium',true,'{"question":"Dịch: ''Nếu anh ấy đã nói với tôi, tôi đã giúp anh ấy rồi.''","sourceText":"Nếu anh ấy đã nói với tôi, tôi đã giúp anh ấy rồi.","acceptedAnswers":["If he had told me, I would have helped him."],"explanationVi":"Loại 3."}'::jsonb),
 ('b1-u10-l2-q5','b1-u10-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối loại điều kiện với mệnh đề if:","pairs":[{"left":"Loại 2","right":"If + past simple"},{"left":"Loại 3","right":"If + past perfect"}],"explanationVi":"Phân biệt loại 2 và loại 3."}'::jsonb),
 ('b1-u10-l2-q6','b1-u10-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu điều kiện loại 3 đúng:","tokens":["If","she","had","known","she","would","have","come"],"correctOrder":[0,1,2,3,4,5,6,7],"explanationVi":"If she had known, she would have come."}'::jsonb),
 ('b1-u10-l2-q7','b1-u10-l2','multiple_choice',14,'quiz','hard',true,'{"question":"Mixed conditional ĐÚNG: (quá khứ ảnh hưởng hiện tại)","options":[{"id":"a","text":"If I had studied medicine, I would be a doctor now."},{"id":"b","text":"If I had studied medicine, I would have been a doctor now."},{"id":"c","text":"If I studied medicine, I would be a doctor now."}],"correctOptionId":"a","explanationVi":"Mixed: If + past perfect, would + base verb (hiện tại)."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u10-l3','B1','listening','b1-u10','normal',3,'Wish & If Only','Ước muốn và hối tiếc',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u10-l3-p1','b1-u10-l3','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu ĐÚNG: Ước mình cao hơn.","options":[{"id":"a","text":"I wish I am taller."},{"id":"b","text":"I wish I were taller."},{"id":"c","text":"I wish I would be taller."}],"correctOptionId":"b","explanationVi":"wish + past simple (were): ước muốn hiện tại."}'::jsonb),
 ('b1-u10-l3-p2','b1-u10-l3','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền vào chỗ trống: ''I wish I ___ (study) harder last year.''","acceptedAnswers":["had studied"],"explanationVi":"Hối tiếc quá khứ: wish + past perfect."}'::jsonb),
 ('b1-u10-l3-p3','b1-u10-l3','vocabulary_match',3,'practice','easy',false,'{"question":"Nối cấu trúc với ý nghĩa:","pairs":[{"left":"wish + past simple","right":"ước muốn hiện tại"},{"left":"wish + past perfect","right":"hối tiếc quá khứ"},{"left":"wish + would","right":"ước thay đổi thói quen"}],"explanationVi":"Phân biệt ba cấu trúc wish."}'::jsonb),
 ('b1-u10-l3-p4','b1-u10-l3','error_correction',4,'practice','medium',false,'{"question":"Sửa lỗi: ''I wish I would have more time.''","acceptedAnswers":["I wish I had more time."],"explanationVi":"wish + past simple cho ước muốn hiện tại."}'::jsonb),
 ('b1-u10-l3-p5','b1-u10-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh: ''Ước tôi đã nói chuyện với cô ấy.''","sourceText":"Ước tôi đã nói chuyện với cô ấy.","acceptedAnswers":["I wish I had talked to her.","I wish I had spoken to her."],"explanationVi":"Hối tiếc quá khứ: wish + past perfect."}'::jsonb),
 ('b1-u10-l3-p6','b1-u10-l3','multiple_choice',6,'practice','medium',false,'{"question":"Chọn câu ''if only'' ĐÚNG: Giá mà tôi đã nghe lời họ!","options":[{"id":"a","text":"If only I listen to them!"},{"id":"b","text":"If only I had listened to them!"},{"id":"c","text":"If only I listened to them!"}],"correctOptionId":"b","explanationVi":"Hối tiếc quá khứ: if only + past perfect."}'::jsonb),
 ('b1-u10-l3-p7','b1-u10-l3','grammar_fill_blank',7,'practice','medium',false,'{"question":"Điền vào chỗ trống: ''I wish you ___ (stop) making so much noise.''","acceptedAnswers":["would stop"],"explanationVi":"Ước về thói quen người khác: wish + would."}'::jsonb),
 ('b1-u10-l3-q1','b1-u10-l3','multiple_choice',8,'quiz','easy',true,'{"question":"Câu nào diễn đạt ước muốn hiện tại ĐÚNG?","options":[{"id":"a","text":"I wish I had more time."},{"id":"b","text":"I wish I had had more time."},{"id":"c","text":"I wish I will have more time."}],"correctOptionId":"a","explanationVi":"wish + past simple = ước muốn hiện tại."}'::jsonb),
 ('b1-u10-l3-q2','b1-u10-l3','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''If only I ___ (not say) that!''","acceptedAnswers":["hadn''t said"],"explanationVi":"Hối tiếc quá khứ: if only + past perfect."}'::jsonb),
 ('b1-u10-l3-q3','b1-u10-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu hối tiếc quá khứ ĐÚNG:","options":[{"id":"a","text":"I wish I didn''t eat so much."},{"id":"b","text":"I wish I hadn''t eaten so much."},{"id":"c","text":"I wish I won''t eat so much."}],"correctOptionId":"b","explanationVi":"Hối tiếc quá khứ: wish + past perfect."}'::jsonb),
 ('b1-u10-l3-q4','b1-u10-l3','translation',11,'quiz','medium',true,'{"question":"Dịch: ''Ước gì bạn không nói vậy.''","sourceText":"Ước gì bạn không nói vậy.","acceptedAnswers":["I wish you hadn''t said that.","If only you hadn''t said that."],"explanationVi":"Hối tiếc quá khứ."}'::jsonb),
 ('b1-u10-l3-q5','b1-u10-l3','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối câu với loại wish:","pairs":[{"left":"I wish I were taller.","right":"ước muốn hiện tại"},{"left":"I wish I had studied.","right":"hối tiếc quá khứ"},{"left":"I wish you would stop.","right":"ước thay đổi thói quen"}],"explanationVi":"Phân biệt ba loại."}'::jsonb),
 ('b1-u10-l3-q6','b1-u10-l3','error_correction',13,'quiz','hard',true,'{"question":"Sửa lỗi: ''I wish I passed the exam.'' (nói về kỳ thi đã qua)","acceptedAnswers":["I wish I had passed the exam."],"explanationVi":"Hối tiếc quá khứ: wish + past perfect."}'::jsonb),
 ('b1-u10-l3-q7','b1-u10-l3','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền vào chỗ trống: ''If only I ___ (take) that job offer!''","acceptedAnswers":["had taken"],"explanationVi":"Hối tiếc quá khứ: if only + had + V3."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u10-l4','B1','listening','b1-u10','normal',4,'A Very Bad Day','Đọc hiểu: Ngày tệ nhất và bài học rút ra',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u10-l4-p1','b1-u10-l4','multiple_choice',1,'practice','easy',false,'{"question":"Tại sao Lan ngủ quên?","options":[{"id":"a","text":"Cô bị ốm"},{"id":"b","text":"Cô quên đặt báo thức"},{"id":"c","text":"Báo thức bị hỏng"}],"correctOptionId":"b","explanationVi":"''forgotten to set her alarm.''"}'::jsonb),
 ('b1-u10-l4-p2','b1-u10-l4','multiple_choice',2,'practice','easy',false,'{"question":"Lan quên mang gì đến cơ quan?","options":[{"id":"a","text":"Chìa khóa"},{"id":"b","text":"Bài thuyết trình"},{"id":"c","text":"Máy tính"}],"correctOptionId":"b","explanationVi":"''left her presentation at home.''"}'::jsonb),
 ('b1-u10-l4-p3','b1-u10-l4','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"oversleep","right":"ngủ quên"},{"left":"deadline","right":"hạn chót"},{"left":"consequence","right":"hậu quả"},{"left":"set an alarm","right":"đặt báo thức"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u10-l4-p4','b1-u10-l4','multiple_choice',4,'practice','medium',false,'{"question":"Loại điều kiện nào trong câu: ''If she had set her alarm, she would have woken up on time.''?","options":[{"id":"a","text":"Loại 1"},{"id":"b","text":"Loại 2"},{"id":"c","text":"Loại 3"}],"correctOptionId":"c","explanationVi":"If + past perfect → loại 3."}'::jsonb),
 ('b1-u10-l4-p5','b1-u10-l4','grammar_fill_blank',5,'practice','medium',false,'{"question":"Hoàn thành theo bài: ''She wished she ___ (go) to bed earlier.''","acceptedAnswers":["had gone"],"explanationVi":"wish + past perfect: wished she had gone."}'::jsonb),
 ('b1-u10-l4-p6','b1-u10-l4','multiple_choice',6,'practice','medium',false,'{"question":"Lan quyết định làm gì để không tái diễn?","options":[{"id":"a","text":"Mua báo thức mới"},{"id":"b","text":"Lập danh sách việc cần làm"},{"id":"c","text":"Đi làm sớm hơn"}],"correctOptionId":"b","explanationVi":"''made a list of things to do the next morning.''"}'::jsonb),
 ('b1-u10-l4-p7','b1-u10-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành: ''If she ___ (check) her bag, she ___ (remember) the presentation.''","acceptedAnswers":["had checked / would have remembered"],"explanationVi":"Loại 3: If + past perfect, would have + V3."}'::jsonb),
 ('b1-u10-l4-q1','b1-u10-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Câu ''I wish I were more organised'' diễn đạt điều gì?","options":[{"id":"a","text":"Hối tiếc quá khứ"},{"id":"b","text":"Ước muốn hiện tại"},{"id":"c","text":"Kế hoạch tương lai"}],"correctOptionId":"b","explanationVi":"wish + past simple = ước muốn hiện tại."}'::jsonb),
 ('b1-u10-l4-q2','b1-u10-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Câu ''If only I had prepared better!'' diễn đạt điều gì?","options":[{"id":"a","text":"Điều kiện tương lai"},{"id":"b","text":"Hối tiếc quá khứ"},{"id":"c","text":"Ước muốn hiện tại"}],"correctOptionId":"b","explanationVi":"if only + past perfect = hối tiếc quá khứ."}'::jsonb),
 ('b1-u10-l4-q3','b1-u10-l4','grammar_fill_blank',10,'quiz','medium',true,'{"question":"Hoàn thành điều kiện loại 3: ''If she ___ (not oversleep), she ___ (not miss) the bus.''","acceptedAnswers":["hadn''t overslept / wouldn''t have missed"],"explanationVi":"Loại 3 phủ định."}'::jsonb),
 ('b1-u10-l4-q4','b1-u10-l4','multiple_choice',11,'quiz','medium',true,'{"question":"Lan sẽ làm gì nếu có ngày tệ nữa?","options":[{"id":"a","text":"Ở nhà"},{"id":"b","text":"Nhờ đồng nghiệp giúp"},{"id":"c","text":"Xin nghỉ phép"}],"correctOptionId":"b","explanationVi":"''would ask her colleague for help.''"}'::jsonb),
 ('b1-u10-l4-q5','b1-u10-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Câu nào mô tả đúng nhất nội dung bài đọc?","options":[{"id":"a","text":"Lan thích ngày thứ Hai"},{"id":"b","text":"Lan học từ những sai lầm và lập kế hoạch cải thiện"},{"id":"c","text":"Lan quyết định nghỉ việc"}],"correctOptionId":"b","explanationVi":"Bài học rút ra từ ngày tệ."}'::jsonb),
 ('b1-u10-l4-q6','b1-u10-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"oversleep","right":"ngủ quên"},{"left":"consequence","right":"hậu quả"},{"left":"set an alarm","right":"đặt báo thức"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b1-u10-l4-q7','b1-u10-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chuyển sang wish: ''She didn''t prepare well.'' → She wished she ___.","acceptedAnswers":["had prepared well","had prepared better"],"explanationVi":"Hối tiếc quá khứ: wish + past perfect."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u10-l5','B1','listening','b1-u10','unit_review',5,'Unit 10 Review','Ôn tập Unit 10: Dealing With Problems',12,30,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u10-l5-q1','b1-u10-l5','multiple_choice',1,'quiz','easy',true,'{"question":"Chọn câu điều kiện loại 2 ĐÚNG:","options":[{"id":"a","text":"If I had a car, I would drive."},{"id":"b","text":"If I would have a car, I drive."},{"id":"c","text":"If I have a car, I would drive."}],"correctOptionId":"a","explanationVi":"Loại 2: If + past simple, would + base verb."}'::jsonb),
 ('b1-u10-l5-q2','b1-u10-l5','grammar_fill_blank',2,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''If I ___ (be) you, I would talk to her.''","acceptedAnswers":["were"],"explanationVi":"If I were you — were cho mọi chủ ngữ."}'::jsonb),
 ('b1-u10-l5-q3','b1-u10-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Chọn câu điều kiện loại 3 ĐÚNG:","options":[{"id":"a","text":"If she had known, she would have come."},{"id":"b","text":"If she would have known, she would come."},{"id":"c","text":"If she knew, she would have come."}],"correctOptionId":"a","explanationVi":"Loại 3: If + past perfect, would have + V3."}'::jsonb),
 ('b1-u10-l5-q4','b1-u10-l5','error_correction',4,'quiz','medium',true,'{"question":"Sửa lỗi: ''I wish I would have more free time.''","acceptedAnswers":["I wish I had more free time."],"explanationVi":"wish + past simple = ước muốn hiện tại."}'::jsonb),
 ('b1-u10-l5-q5','b1-u10-l5','grammar_fill_blank',5,'quiz','medium',true,'{"question":"Điền vào chỗ trống: ''I wish I ___ (not say) that to her.''","acceptedAnswers":["hadn''t said"],"explanationVi":"Hối tiếc quá khứ: wish + past perfect."}'::jsonb),
 ('b1-u10-l5-q6','b1-u10-l5','multiple_choice',6,'quiz','medium',true,'{"question":"Câu nào là ''if only'' ĐÚNG?","options":[{"id":"a","text":"If only I listen to them!"},{"id":"b","text":"If only I had listened to them!"},{"id":"c","text":"If only I listened to them!"}],"correctOptionId":"b","explanationVi":"Hối tiếc quá khứ: if only + past perfect."}'::jsonb),
 ('b1-u10-l5-q7','b1-u10-l5','translation',7,'quiz','medium',true,'{"question":"Dịch: ''Giá mà tôi đã học y khoa.''","sourceText":"Giá mà tôi đã học y khoa.","acceptedAnswers":["If only I had studied medicine.","I wish I had studied medicine."],"explanationVi":"Hối tiếc quá khứ."}'::jsonb),
 ('b1-u10-l5-q8','b1-u10-l5','multiple_choice',8,'quiz','hard',true,'{"question":"Câu nào là mixed conditional ĐÚNG?","options":[{"id":"a","text":"If I had taken that job, I would be rich now."},{"id":"b","text":"If I took that job, I would have been rich."},{"id":"c","text":"If I would have taken that job, I would be rich."}],"correctOptionId":"a","explanationVi":"Mixed: If + past perfect, would + base verb (hiện tại)."}'::jsonb),
 ('b1-u10-l5-q9','b1-u10-l5','error_correction',9,'quiz','medium',true,'{"question":"Sửa lỗi: ''If they would have called, we would have known.''","acceptedAnswers":["If they had called, we would have known."],"explanationVi":"Mệnh đề if: past perfect (không would have)."}'::jsonb),
 ('b1-u10-l5-q10','b1-u10-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Điền vào chỗ trống: ''If she ___ (study) harder, she ___ (pass) the exam.'' (Loại 3)","acceptedAnswers":["had studied / would have passed"],"explanationVi":"Loại 3: had + V3 / would have + V3."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u11-l1','B1','reading','b1-u11','normal',1,'Passive Voice — Present & Past','be + V3; by agent; when to use passive',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u11-l1-p1','b1-u11-l1','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu bị động ĐÚNG (hiện tại đơn):","options":[{"id":"a","text":"English speak in many countries."},{"id":"b","text":"English is spoken in many countries."},{"id":"c","text":"English is speak in many countries."}],"correctOptionId":"b","explanationVi":"Bị động hiện tại: is/are + V3."}'::jsonb),
 ('b1-u11-l1-p2','b1-u11-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Chuyển sang bị động: ''They built the school in 1990.'' → The school ___ in 1990.","acceptedAnswers":["was built"],"explanationVi":"Quá khứ bị động: was/were + V3."}'::jsonb),
 ('b1-u11-l1-p3','b1-u11-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối câu chủ động với câu bị động:","pairs":[{"left":"They grow rice here.","right":"Rice is grown here."},{"left":"Someone stole my bag.","right":"My bag was stolen."},{"left":"A teacher explains the rules.","right":"The rules are explained by a teacher."}],"explanationVi":"Ghép đúng từng cặp."}'::jsonb),
