 ('b1-u11-l1-p5','b1-u11-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh (bị động): ''Phở được ăn khắp Việt Nam.''","sourceText":"Phở được ăn khắp Việt Nam.","acceptedAnswers":["Pho is eaten all over Vietnam.","Pho is eaten throughout Vietnam."],"explanationVi":"Bị động hiện tại: is + V3."}'::jsonb),
 ('b1-u11-l1-p6','b1-u11-l1','multiple_choice',6,'practice','medium',false,'{"question":"Khi nào KHÔNG cần thêm by + agent?","options":[{"id":"a","text":"Khi tác nhân quan trọng"},{"id":"b","text":"Khi không biết hoặc không quan trọng ai làm"},{"id":"c","text":"Khi câu ở quá khứ"}],"correctOptionId":"b","explanationVi":"by + agent chỉ thêm khi cần thiết."}'::jsonb),
 ('b1-u11-l1-p7','b1-u11-l1','grammar_fill_blank',7,'practice','medium',false,'{"question":"Chuyển sang bị động: ''Hemingway wrote this novel.'' → This novel ___ by Hemingway.","acceptedAnswers":["was written"],"explanationVi":"Quá khứ bị động: was + V3."}'::jsonb),
 ('b1-u11-l1-q1','b1-u11-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Câu bị động ĐÚNG (quá khứ đơn):","options":[{"id":"a","text":"The bridge was builded in 1960."},{"id":"b","text":"The bridge was built in 1960."},{"id":"c","text":"The bridge is built in 1960."}],"correctOptionId":"b","explanationVi":"Quá khứ bị động: was + V3 (built)."}'::jsonb),
 ('b1-u11-l1-q2','b1-u11-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''French ___ (speak) in many African countries.''","acceptedAnswers":["is spoken"],"explanationVi":"Bị động hiện tại: is + V3."}'::jsonb),
 ('b1-u11-l1-q3','b1-u11-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chuyển câu: ''People make silk in Hội An.'' → Silk ___ in Hội An.","options":[{"id":"a","text":"is make"},{"id":"b","text":"is made"},{"id":"c","text":"was made"}],"correctOptionId":"b","explanationVi":"Bị động hiện tại: is made."}'::jsonb),
 ('b1-u11-l1-q4','b1-u11-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chuyển sang bị động: ''Someone repaired the car.'' → The car ___.","acceptedAnswers":["was repaired"],"explanationVi":"Quá khứ bị động: was + V3."}'::jsonb),
 ('b1-u11-l1-q5','b1-u11-l1','error_correction',12,'quiz','medium',true,'{"question":"Sửa lỗi: ''The film is direct by Nolan.''","acceptedAnswers":["The film is directed by Nolan."],"explanationVi":"Bị động: is + V3 (directed)."}'::jsonb),
 ('b1-u11-l1-q6','b1-u11-l1','translation',13,'quiz','hard',true,'{"question":"Dịch: ''Chùa Một Cột được xây dựng vào thế kỷ 11.''","sourceText":"Chùa Một Cột được xây dựng vào thế kỷ 11.","acceptedAnswers":["The One Pillar Pagoda was built in the 11th century."],"explanationVi":"Quá khứ bị động: was built."}'::jsonb),
 ('b1-u11-l1-q7','b1-u11-l1','sentence_ordering',14,'quiz','hard',true,'{"question":"Sắp xếp thành câu bị động đúng:","tokens":["The","rules","are","explained","by","the","teacher"],"correctOrder":[0,1,2,3,4,5,6],"explanationVi":"The rules are explained by the teacher."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u11-l2','B1','reading','b1-u11','normal',2,'Passive — Perfect & Future','have been + V3; will be + V3',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u11-l2-p1','b1-u11-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu bị động ĐÚNG (hiện tại hoàn thành):","options":[{"id":"a","text":"Three people have arrested."},{"id":"b","text":"Three people have been arrested."},{"id":"c","text":"Three people had been arrested."}],"correctOptionId":"b","explanationVi":"HTTB bị động: have/has been + V3."}'::jsonb),
 ('b1-u11-l2-p2','b1-u11-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Chuyển sang bị động tương lai: ''They will open the new library.'' → The new library ___ next month.","acceptedAnswers":["will be opened"],"explanationVi":"Tương lai bị động: will be + V3."}'::jsonb),
 ('b1-u11-l2-p3','b1-u11-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối câu chủ động với bị động:","pairs":[{"left":"They have completed the project.","right":"The project has been completed."},{"left":"They will announce the results.","right":"The results will be announced."},{"left":"They are repairing the road.","right":"The road is being repaired."}],"explanationVi":"Ghép đúng từng cặp."}'::jsonb),
 ('b1-u11-l2-p4','b1-u11-l2','error_correction',4,'practice','medium',false,'{"question":"Sửa lỗi: ''The bridge will built next year.''","acceptedAnswers":["The bridge will be built next year."],"explanationVi":"Tương lai bị động: will + be + V3."}'::jsonb),
 ('b1-u11-l2-p5','b1-u11-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh: ''Tuyến metro mới sẽ được khai trương vào năm tới.''","sourceText":"Tuyến metro mới sẽ được khai trương vào năm tới.","acceptedAnswers":["The new metro line will be opened next year.","A new metro line will be opened next year."],"explanationVi":"Tương lai bị động: will be opened."}'::jsonb),
 ('b1-u11-l2-p6','b1-u11-l2','multiple_choice',6,'practice','medium',false,'{"question":"Chọn câu bị động tiếp diễn ĐÚNG:","options":[{"id":"a","text":"The road is repaired."},{"id":"b","text":"The road is being repaired."},{"id":"c","text":"The road has been repaired."}],"correctOptionId":"b","explanationVi":"Bị động tiếp diễn: is/are being + V3."}'::jsonb),
 ('b1-u11-l2-p7','b1-u11-l2','grammar_fill_blank',7,'practice','medium',false,'{"question":"Điền vào chỗ trống: ''Five people ___ (rescue — HTTB) from the flood.''","acceptedAnswers":["have been rescued"],"explanationVi":"HTTB bị động: have been + V3."}'::jsonb),
 ('b1-u11-l2-q1','b1-u11-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Câu bị động ĐÚNG (HTTB):","options":[{"id":"a","text":"The prize has given to her."},{"id":"b","text":"The prize has been given to her."},{"id":"c","text":"The prize was been given to her."}],"correctOptionId":"b","explanationVi":"HTTB bị động: has been + V3."}'::jsonb),
 ('b1-u11-l2-q2','b1-u11-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''A new law ___ (introduce — tương lai) next month.''","acceptedAnswers":["will be introduced"],"explanationVi":"Tương lai bị động: will be + V3."}'::jsonb),
 ('b1-u11-l2-q3','b1-u11-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Thì nào của câu bị động: ''The results will be announced tomorrow.''?","options":[{"id":"a","text":"Hiện tại hoàn thành"},{"id":"b","text":"Quá khứ đơn"},{"id":"c","text":"Tương lai"}],"correctOptionId":"c","explanationVi":"will be + V3 = tương lai bị động."}'::jsonb),
 ('b1-u11-l2-q4','b1-u11-l2','error_correction',11,'quiz','medium',true,'{"question":"Sửa lỗi: ''The new school has been complete.''","acceptedAnswers":["The new school has been completed."],"explanationVi":"HTTB bị động: has been + V3 (completed)."}'::jsonb),
 ('b1-u11-l2-q5','b1-u11-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối thì với cấu trúc bị động:","pairs":[{"left":"Hiện tại đơn","right":"is/are + V3"},{"left":"HTTB","right":"have/has been + V3"},{"left":"Tương lai","right":"will be + V3"}],"explanationVi":"Tổng hợp bị động."}'::jsonb),
 ('b1-u11-l2-q6','b1-u11-l2','translation',13,'quiz','hard',true,'{"question":"Dịch: ''Năm người đã được giải cứu khỏi lũ lụt.''","sourceText":"Năm người đã được giải cứu khỏi lũ lụt.","acceptedAnswers":["Five people have been rescued from the flood."],"explanationVi":"HTTB bị động."}'::jsonb),
 ('b1-u11-l2-q7','b1-u11-l2','sentence_ordering',14,'quiz','hard',true,'{"question":"Sắp xếp thành câu bị động đúng:","tokens":["A","new","hospital","will","be","built","next","year"],"correctOrder":[0,1,2,3,4,5,6,7],"explanationVi":"A new hospital will be built next year."}'::jsonb);
