 ('b1-u11-l3','B1','reading','b1-u11','normal',3,'Environment & Causative Have/Get','Từ vựng môi trường + have/get something done',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u11-l3-p1','b1-u11-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"pollution","right":"ô nhiễm"},{"left":"recycle","right":"tái chế"},{"left":"deforestation","right":"nạn phá rừng"},{"left":"endangered","right":"có nguy cơ tuyệt chủng"}],"explanationVi":"Từ vựng môi trường."}'::jsonb),
 ('b1-u11-l3-p2','b1-u11-l3','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu causative ĐÚNG:","options":[{"id":"a","text":"I had repaired my car."},{"id":"b","text":"I had my car repaired."},{"id":"c","text":"I had my car repair."}],"correctOptionId":"b","explanationVi":"Causative: have + object + V3."}'::jsonb),
 ('b1-u11-l3-p3','b1-u11-l3','grammar_fill_blank',3,'practice','easy',false,'{"question":"Điền vào chỗ trống: ''She got her hair ___ (cut) at the salon.''","acceptedAnswers":["cut"],"explanationVi":"get + object + V3 (cut)."}'::jsonb),
 ('b1-u11-l3-p4','b1-u11-l3','vocabulary_match',4,'practice','medium',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"renewable energy","right":"năng lượng tái tạo"},{"left":"carbon footprint","right":"dấu carbon"},{"left":"habitat","right":"môi trường sống"},{"left":"climate change","right":"biến đổi khí hậu"}],"explanationVi":"Từ vựng môi trường nâng cao."}'::jsonb),
 ('b1-u11-l3-p5','b1-u11-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh: ''Tôi nhờ sửa điện thoại ở cửa hàng.''","sourceText":"Tôi nhờ sửa điện thoại ở cửa hàng.","acceptedAnswers":["I had my phone fixed at the shop.","I got my phone fixed at the shop."],"explanationVi":"Causative: have/get + obj + V3."}'::jsonb),
 ('b1-u11-l3-p6','b1-u11-l3','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''She got cut her hair short.''","acceptedAnswers":["She got her hair cut short."],"explanationVi":"get + object + V3: object (her hair) đứng trước V3 (cut)."}'::jsonb),
 ('b1-u11-l3-p7','b1-u11-l3','multiple_choice',7,'practice','medium',false,'{"question":"Từ nào mô tả nguồn năng lượng từ mặt trời và gió?","options":[{"id":"a","text":"fossil fuel"},{"id":"b","text":"renewable energy"},{"id":"c","text":"nuclear energy"}],"correctOptionId":"b","explanationVi":"Mặt trời, gió → renewable energy."}'::jsonb),
 ('b1-u11-l3-q1','b1-u11-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"pollution","right":"ô nhiễm"},{"left":"recycle","right":"tái chế"},{"left":"endangered","right":"có nguy cơ tuyệt chủng"}],"explanationVi":"Từ vựng môi trường."}'::jsonb),
 ('b1-u11-l3-q2','b1-u11-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Câu causative ĐÚNG:","options":[{"id":"a","text":"I got my teeth check last month."},{"id":"b","text":"I got my teeth checked last month."},{"id":"c","text":"I got checked my teeth last month."}],"correctOptionId":"b","explanationVi":"get + obj + V3: my teeth checked."}'::jsonb),
 ('b1-u11-l3-q3','b1-u11-l3','grammar_fill_blank',10,'quiz','medium',true,'{"question":"Điền vào chỗ trống: ''He''s having his roof ___ (repair) after the storm.''","acceptedAnswers":["repaired"],"explanationVi":"have + obj + V3: repaired."}'::jsonb),
 ('b1-u11-l3-q4','b1-u11-l3','multiple_choice',11,'quiz','medium',true,'{"question":"''I had my car repaired'' nghĩa là gì?","options":[{"id":"a","text":"Tôi tự sửa xe"},{"id":"b","text":"Xe tôi bị hỏng"},{"id":"c","text":"Tôi nhờ người khác sửa xe"}],"correctOptionId":"c","explanationVi":"Causative = nhờ/thuê ai đó làm."}'::jsonb),
 ('b1-u11-l3-q5','b1-u11-l3','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với định nghĩa:","pairs":[{"left":"deforestation","right":"chặt phá rừng quy mô lớn"},{"left":"carbon footprint","right":"lượng CO2 cá nhân thải ra"},{"left":"renewable energy","right":"năng lượng không cạn kiệt"}],"explanationVi":"Từ vựng môi trường."}'::jsonb),
 ('b1-u11-l3-q6','b1-u11-l3','translation',13,'quiz','hard',true,'{"question":"Dịch: ''Cô ấy sẽ nhờ kiểm tra mắt vào tuần tới.''","sourceText":"Cô ấy sẽ nhờ kiểm tra mắt vào tuần tới.","acceptedAnswers":["She is going to get her eyes tested next week.","She will have her eyes tested next week."],"explanationVi":"Causative tương lai."}'::jsonb),
 ('b1-u11-l3-q7','b1-u11-l3','error_correction',14,'quiz','hard',true,'{"question":"Sửa lỗi: ''They had their house paint last summer.''","acceptedAnswers":["They had their house painted last summer."],"explanationVi":"have + obj + V3: painted."}'::jsonb);
