INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u11-l4-p1','b1-u11-l4','multiple_choice',1,'practice','easy',false,'{"question":"Theo bài, CO2 chủ yếu được thải ra bởi điều gì?","options":[{"id":"a","text":"Núi lửa"},{"id":"b","text":"Ô tô, nhà máy và nhà máy điện"},{"id":"c","text":"Rừng nhiệt đới"}],"correctOptionId":"b","explanationVi":"''cars, factories, and power stations.''"}'::jsonb),
 ('b1-u11-l4-p2','b1-u11-l4','multiple_choice',2,'practice','easy',false,'{"question":"Ở Việt Nam, điều gì đang bị ảnh hưởng bởi mực nước biển?","options":[{"id":"a","text":"Rừng núi"},{"id":"b","text":"Vùng ven biển"},{"id":"c","text":"Đồng bằng sông Cửu Long"}],"correctOptionId":"b","explanationVi":"''coastal areas are being affected.''"}'::jsonb),
 ('b1-u11-l4-p3','b1-u11-l4','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"global warming","right":"nóng lên toàn cầu"},{"left":"glacier","right":"sông băng"},{"left":"species","right":"loài sinh vật"},{"left":"emit","right":"thải ra"}],"explanationVi":"Từ vựng môi trường."}'::jsonb),
 ('b1-u11-l4-p4','b1-u11-l4','multiple_choice',4,'practice','medium',false,'{"question":"Câu ''New laws have been introduced'' là thì gì của bị động?","options":[{"id":"a","text":"Quá khứ đơn"},{"id":"b","text":"Hiện tại hoàn thành"},{"id":"c","text":"Tương lai"}],"correctOptionId":"b","explanationVi":"have been + V3 = HTTB bị động."}'::jsonb),
 ('b1-u11-l4-p5','b1-u11-l4','multiple_choice',5,'practice','medium',false,'{"question":"Người dân đang được khuyến khích làm gì?","options":[{"id":"a","text":"Dùng ít điện hơn"},{"id":"b","text":"Tái chế và giảm dấu carbon"},{"id":"c","text":"Trồng thêm cây"}],"correctOptionId":"b","explanationVi":"''recycle more and reduce their carbon footprints.''"}'::jsonb),
 ('b1-u11-l4-p6','b1-u11-l4','grammar_fill_blank',6,'practice','medium',false,'{"question":"Hoàn thành câu bị động theo bài: ''The planet must ___ protected.''","acceptedAnswers":["be"],"explanationVi":"Modal + be + V3: must be protected."}'::jsonb),
 ('b1-u11-l4-p7','b1-u11-l4','multiple_choice',7,'practice','medium',false,'{"question":"Câu ''it can still be saved'' diễn đạt điều gì?","options":[{"id":"a","text":"Hành tinh sẽ tự cứu"},{"id":"b","text":"Con người có thể cứu hành tinh"},{"id":"c","text":"Hành tinh không thể cứu được"}],"correctOptionId":"b","explanationVi":"can be saved = có thể được cứu."}'::jsonb),
 ('b1-u11-l4-q1','b1-u11-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Theo bài, điều gì đã tăng đều đặn?","options":[{"id":"a","text":"Lượng mưa"},{"id":"b","text":"Nhiệt độ toàn cầu"},{"id":"c","text":"Diện tích rừng"}],"correctOptionId":"b","explanationVi":"''global temperatures have been rising steadily.''"}'::jsonb),
 ('b1-u11-l4-q2','b1-u11-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Câu bị động nào trong bài ở thì quá khứ đơn?","options":[{"id":"a","text":"are released"},{"id":"b","text":"have been melted"},{"id":"c","text":"were introduced (nếu dùng quá khứ)"}],"correctOptionId":"b","explanationVi":"Nhận biết thì bị động qua cấu trúc."}'::jsonb),
 ('b1-u11-l4-q3','b1-u11-l4','grammar_fill_blank',10,'quiz','medium',true,'{"question":"Hoàn thành theo bài: ''Renewable energy projects ___ (fund — HTTB) across the country.''","acceptedAnswers":["have been funded"],"explanationVi":"HTTB bị động: have been + V3."}'::jsonb),
 ('b1-u11-l4-q4','b1-u11-l4','multiple_choice',11,'quiz','medium',true,'{"question":"Câu ''Citizens are being encouraged to recycle'' là thì gì của bị động?","options":[{"id":"a","text":"Bị động tiếp diễn"},{"id":"b","text":"Bị động tương lai"},{"id":"c","text":"Bị động quá khứ"}],"correctOptionId":"a","explanationVi":"are being + V3 = bị động tiếp diễn."}'::jsonb),
 ('b1-u11-l4-q5','b1-u11-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Điều nhà khoa học cảnh báo nếu không hành động?","options":[{"id":"a","text":"Nhiệt độ sẽ ổn định"},{"id":"b","text":"Hậu quả sẽ rất nghiêm trọng"},{"id":"c","text":"Sẽ không còn ô nhiễm"}],"correctOptionId":"b","explanationVi":"''the consequences will be severe.''"}'::jsonb),
 ('b1-u11-l4-q6','b1-u11-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"glacier","right":"sông băng"},{"left":"species","right":"loài sinh vật"},{"left":"emit","right":"thải ra"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b1-u11-l4-q7','b1-u11-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chuyển sang bị động: ''They have declared several species endangered.'' → Several species ___.","acceptedAnswers":["have been declared endangered"],"explanationVi":"HTTB bị động: have been + V3."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u11-l5','B1','reading','b1-u11','unit_review',5,'Unit 11 Review','Ôn tập Unit 11: The World Around Us',12,30,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u11-l5-q1','b1-u11-l5','multiple_choice',1,'quiz','easy',true,'{"question":"Câu bị động hiện tại ĐÚNG:","options":[{"id":"a","text":"Rice grow in Vietnam."},{"id":"b","text":"Rice is grown in Vietnam."},{"id":"c","text":"Rice is grow in Vietnam."}],"correctOptionId":"b","explanationVi":"Bị động hiện tại: is + V3."}'::jsonb),
 ('b1-u11-l5-q2','b1-u11-l5','grammar_fill_blank',2,'quiz','easy',true,'{"question":"Điền vào chỗ trống: ''The museum ___ (build — quá khứ) in 1920.''","acceptedAnswers":["was built"],"explanationVi":"Quá khứ bị động: was + V3."}'::jsonb),
 ('b1-u11-l5-q3','b1-u11-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Câu HTTB bị động ĐÚNG:","options":[{"id":"a","text":"The award have been given to her."},{"id":"b","text":"The award has been given to her."},{"id":"c","text":"The award was been given to her."}],"correctOptionId":"b","explanationVi":"HTTB bị động: has been + V3."}'::jsonb),
 ('b1-u11-l5-q4','b1-u11-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Điền vào chỗ trống: ''A new bridge ___ (build — tương lai) next year.''","acceptedAnswers":["will be built"],"explanationVi":"Tương lai bị động: will be + V3."}'::jsonb),
 ('b1-u11-l5-q5','b1-u11-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu causative ĐÚNG:","options":[{"id":"a","text":"I had repaired my car."},{"id":"b","text":"I had my car repaired."},{"id":"c","text":"I had my car repair."}],"correctOptionId":"b","explanationVi":"Causative: have + obj + V3."}'::jsonb),
 ('b1-u11-l5-q6','b1-u11-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ môi trường với nghĩa:","pairs":[{"left":"pollution","right":"ô nhiễm"},{"left":"recycle","right":"tái chế"},{"left":"renewable energy","right":"năng lượng tái tạo"},{"left":"endangered","right":"có nguy cơ tuyệt chủng"}],"explanationVi":"Từ vựng môi trường."}'::jsonb),
 ('b1-u11-l5-q7','b1-u11-l5','error_correction',7,'quiz','medium',true,'{"question":"Sửa lỗi: ''She got cut her hair short.''","acceptedAnswers":["She got her hair cut short."],"explanationVi":"get + obj + V3: obj đứng trước V3."}'::jsonb),
 ('b1-u11-l5-q8','b1-u11-l5','multiple_choice',8,'quiz','hard',true,'{"question":"Thì nào: ''The road is being repaired''?","options":[{"id":"a","text":"Bị động tiếp diễn"},{"id":"b","text":"Bị động hiện tại đơn"},{"id":"c","text":"HTTB bị động"}],"correctOptionId":"a","explanationVi":"is being + V3 = bị động tiếp diễn."}'::jsonb),
 ('b1-u11-l5-q9','b1-u11-l5','grammar_fill_blank',9,'quiz','medium',true,'{"question":"Chuyển sang bị động: ''They are announcing the results.'' → The results ___.","acceptedAnswers":["are being announced"],"explanationVi":"Bị động tiếp diễn: are being + V3."}'::jsonb),
 ('b1-u11-l5-q10','b1-u11-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Điền vào chỗ trống: ''He''s going to have his house ___ (paint) this summer.''","acceptedAnswers":["painted"],"explanationVi":"Causative: have + obj + V3 (painted)."}'::jsonb);
